<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Amortización</title><link rel="stylesheet" href="/styles/styles.css"><link rel="icon" href="/img/Icon.ico"></head><body>@include('pages.partials.header')<main class="container"><h2 class="calc-title">Amortización</h2><p class="calc-subtitle">Simulador de crédito con cuota fija (sistema francés). Genera la tabla completa de pagos.</p><div class="formula">Cuota = VP · i / [1 - (1 + i)⁻ⁿ]</div><section><div class="card"><div class="grid-3"><div class="field"><label>Monto del crédito</label><div class="input-wrap"><input id="cred" type="number"><span>$</span></div></div><div class="field"><label>Tasa por periodo (i)</label><div class="input-wrap"><input id="iC" type="number"><span>%</span></div></div><div class="field"><label>Número de cuotas (n)</label><input id="nC" type="number"></div><div><button id="calc-amort">Generar tabla</button></div></div><div id="result" class="result-value mt"></div></div></section></main>@include('pages.partials.footer')<script src="/js/calculadora.js"></script></body></html>
